```plantuml
@startuml
package Hugobot {
  package time_intervals_adapter {
    class TimeIntervalsAdapter {
      - max_gap
      + connect_timestamps(df, epsilon=1)
      + create_time_intervals(symbolic_time_series)
    }
  }

  package kfold {
    class KFold {
      - nb_folds
      - entity_class_relations
      + divide_dataset(dataset)
    }
  }

  package abstraction_per_property {
    class AbstractionPerProperty {
      - preprocessing_params_df
      - temporal_abstraction_params_df
      + preprocessing_per_property(dataset)
      + temporal_abstraction_per_property(dataset, entity_class_relations=None, states=None)
      + intervalization_per_property(symbolic_time_series)
      - generate_preprocessing_by_name(params_row)
      - generate_abstraction_by_name(params_row, entity_class_relations=None, states=None)
    }
  }

  package preprocessing {
    class Transformation {
      + transform(dataset)
    }
    class PAA {
      - window_size
      + transform(dataset)
    }
    class OutliersRemover {
      - std_coef
      + transform(dataset)
    }
    Transformation <|-- PAA
    Transformation <|-- OutliersRemover
  }

  package temporal_abstraction {
    abstract class TemporalAbstraction {
      + discretize_property(prop_df)
      + discretize_to_bins(cutpoints, values)
      + create_symbolic_time_series(states, time_point_series)
      + extract_cutpoints_from_states(states)
    }
    class Gradient <<Node>> {
      - window_size
      - states
      + discretize_property(prop_df)
      + gradient(df, window_size, states)
      + derivative(df, gradient_window_size)
    }
    class KnowledgeBased <<Node>> {
      - states
      + discretize_property(prop_df)
      + knowledge_based(states, prop_df)
    }
    TemporalAbstraction <|-- Gradient
    TemporalAbstraction <|-- KnowledgeBased

    package discretization {
      abstract class Discretization {
        ~ nb_bins
        ~ generate_cutpoints(prop_df)
        + discretize_property(prop_df)
        + create_prop_states(prop_id, cutpoints, scores)
      }
      abstract class Unsupervised {
      }
      abstract class Supervised {
        ~ entity_class_relations
      }
      TemporalAbstraction <|-- Discretization
      Discretization <|-- Unsupervised
      Discretization <|-- Supervised

      package methods {
        class EqualWidth {
          + generate_cutpoints(...) : List[cutpoints]
          - equal_width(...)
        }
        class EqualFrequency {
          + generate_cutpoints(...) : List[cutpoints]
          - equal_frequency(...)
        }
        class KMeans {
          + generate_cutpoints(...) : List[cutpoints]
          - kmeans_adapter(...)
        }
        class SAX {
          + generate_cutpoints(...) : List[cutpoints]
          - sax(...)
        }
        Unsupervised <|-- EqualWidth
        Unsupervised <|-- EqualFrequency
        Unsupervised <|-- KMeans
        Unsupervised <|-- SAX

        package td4c_persist {
          class Persist {
            - persist(...)
            - all_states_persistence()
            - single_state_persistence()
            - calc_state_probabilities()
            - calc_marginal_probabilities()
          }
          class shared_functions {
            ~ candidate_selection()
            ~ generate_candidate_cutpoints()
            ~ symmetric_kullback_leibler()
          }
          abstract class TD4C {
            - DDM_scoring_function(df, cutoffs, entity_class_relations)
            - distance_measure(p, q)
          }
          class TD4C_Cosine {
            - distance_measure(p, q)
          }
          class TD4C_Kullback_Leibler {
            - distance_measure(p, q)
          }
          class TD4C_Entropy {
            - distance_measure(p, q)
          }
          class TD4C_Entropy_IG {
            - distance_measure(p, q)
          }
          Supervised <|-- TD4C
          TD4C <|-- TD4C_Cosine
          TD4C <|-- TD4C_Kullback_Leibler
          TD4C <|-- TD4C_Entropy
          TD4C <|-- TD4C_Entropy_IG
        }
      }
    }
  }

  KFold --> AbstractionPerProperty
  AbstractionPerProperty --> time_intervals_adapter
  AbstractionPerProperty --> preprocessing
  AbstractionPerProperty --> temporal_abstraction
}
@enduml
